// Aktecontrole: classificeer geuploade bestanden op veldnaam-prefix.
//   akte_* -> role 'akte' (akte van levering)
//   bron_* -> role 'bron' (brondocument)
// Bouwt per bestand een Docling-item (base64). Vereist minstens één van elke rol.
const webhookItem = $input.first();
const b = (webhookItem && webhookItem.binary) || {};
const keys = Object.keys(b);

if (keys.length === 0) {
  throw new Error(
    'Webhook ontving geen binary bestanden. Stuur de akte van levering (veld akte_*) en het brondocument (veld bron_*) als multipart/form-data mee.'
  );
}

function isConvertibleDoc(k) {
  const fn = String(b[k]?.fileName || '').toLowerCase();
  const mime = String(b[k]?.mimeType || '').toLowerCase();
  if (fn.endsWith('.pdf') || mime.includes('pdf')) return true;
  if (fn.endsWith('.docx')) return true;
  if (mime.includes('wordprocessingml') || mime.includes('officedocument.wordprocessingml')) return true;
  return false;
}

function roleForKey(k) {
  const lk = String(k).toLowerCase();
  if (lk.startsWith('akte')) return 'akte';
  if (lk.startsWith('bron')) return 'bron';
  return null;
}

async function loadAsBase64(binaryKey) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
  return buffer.toString('base64');
}

const docKeys = keys.filter(isConvertibleDoc);
if (docKeys.length === 0) {
  throw new Error('Geen ondersteunde documenten (PDF of .docx) in de upload.');
}

const roles = new Set();
const out = [];
for (const k of docKeys) {
  const role = roleForKey(k);
  if (!role) continue; // negeer onbekende velden
  roles.add(role);
  const blob = await loadAsBase64.call(this, k);
  out.push({
    json: {
      role,
      filename: b[k]?.fileName || `${k}.pdf`,
      base64_string: blob,
      receivedAt: new Date().toISOString(),
    },
  });
}

if (!roles.has('akte')) {
  throw new Error("Geen 'akte van levering' ontvangen. Upload het bestand in een veld dat begint met 'akte' (akte_0, akte_1, ...).");
}
if (!roles.has('bron')) {
  throw new Error("Geen 'brondocument' ontvangen. Upload het bestand in een veld dat begint met 'bron' (bron_0, bron_1, ...).");
}

return out;

// Per Docling-response: pak de markdown en bewaar role + bestandsnaam.
const sourceItem = $('Split Input Files').itemMatching($itemIndex);
const role = sourceItem?.json?.role || $json.role || 'overig';
const filename = sourceItem?.json?.filename || '';

const payload = $json;
let md = '';
if (payload?.document?.md_content) md = payload.document.md_content;
else if (payload?.md_content) md = payload.md_content;
else if (payload?.result?.document?.md_content) md = payload.result.document.md_content;
else if (Array.isArray(payload?.documents) && payload.documents[0]?.md_content) md = payload.documents[0].md_content;

if (!md) {
  throw new Error(`Docling gaf geen md_content terug voor ${filename || role}. Top-level keys: ${Object.keys(payload || {}).join(', ')}`);
}

return { json: { role, filename, markdown: md } };

// Splitst de geëxtraheerde markdowns op rol (akte van levering vs brondocument)
// en bundelt ze tot twee tekstblokken voor de vergelijkings-LLM.
const items = $input.all();
if (!items.length) {
  throw new Error('Geen markdowns ontvangen voor de aktecontrole.');
}

const MAX_PER_DOC = 12000;
function clamp(s, max) {
  const txt = String(s || '');
  if (txt.length <= max) return txt;
  return txt.slice(0, max) + '\n…[afgekapt voor controle-prompt]';
}

const akteDocs = [];
const bronDocs = [];
for (const it of items) {
  const j = it.json || {};
  const entry = { filename: j.filename || '', markdown: clamp(j.markdown || '', MAX_PER_DOC) };
  if (j.role === 'akte') akteDocs.push(entry);
  else if (j.role === 'bron') bronDocs.push(entry);
}

if (akteDocs.length === 0) throw new Error('Geen markdown voor de akte van levering na extractie.');
if (bronDocs.length === 0) throw new Error('Geen markdown voor het brondocument na extractie.');

function joinDocs(list) {
  return list.map((d, i) => `=== ${d.filename || ('document ' + (i + 1))} ===\n${d.markdown}`).join('\n\n');
}

const now = new Date();
const zaaknummer = `${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, '0')}${String(now.getDate()).padStart(2, '0')}_${String(now.getHours()).padStart(2, '0')}${String(now.getMinutes()).padStart(2, '0')}${String(now.getSeconds()).padStart(2, '0')}`;

return [{
  json: {
    akteMarkdown: joinDocs(akteDocs),
    bronMarkdown: joinDocs(bronDocs),
    akteFilename: akteDocs.map((d) => d.filename).filter(Boolean).join(', '),
    bronFilename: bronDocs.map((d) => d.filename).filter(Boolean).join(', '),
    documentCount: akteDocs.length + bronDocs.length,
    zaaknummer,
  },
}];

// Schrijf de akte-markdown naar een tijdelijk JSON-bestand voor
// controleer_spelling.py (zelfopruimend: script verwijdert het na inlezen).
const fs = require('fs');
const execId = String($execution.id || 'single').replace(/[^0-9A-Za-z_-]/g, '_').slice(0, 32);
const argsFile = `/tmp/n8n_args_spelling_${execId}_${Date.now()}.json`;
const agg = $('Aggregate Inputs').first()?.json || {};
fs.writeFileSync(argsFile, JSON.stringify({ akteMarkdown: String(agg.akteMarkdown || '') }), 'utf8');
return { json: { ...$json, argsFile } };

// Parse de stdout van controleer_spelling.py: 'SUCCESS: <json-array>'.
const cmd = $('Detecteer Spelling').first()?.json || {};
const stdout = String(cmd.stdout || '');
const stderr = String(cmd.stderr || '');

let arr = [];
const m = stdout.match(/SUCCESS:\s*([\s\S]+)$/);
const jsonText = (m ? m[1] : stdout).trim();
try {
  const p = JSON.parse(jsonText);
  if (Array.isArray(p)) arr = p;
} catch (e) {
  // Geen bruikbare output: ga verder met lege kandidatenlijst.
}

return [{
  json: {
    candidates: arr,
    candidateCount: arr.length,
    spelling_warning: arr.length === 0 && stderr ? stderr.slice(0, 200) : null,
  },
}];

// Bouwt de prompt die het LLM gebruikt om valse positieven uit de
// spellchecker-kandidaten te filteren.
const fs = require('fs');
const REGISTRY_PATH = '/data/shared/templates/registry.json';

let registry;
try {
  registry = JSON.parse(fs.readFileSync(REGISTRY_PATH, 'utf8'));
} catch (err) {
  throw new Error(`Kon templates-registry niet lezen (${REGISTRY_PATH}): ${err.message}`);
}

const basePrompt = String(registry.spelling_filter_prompt || '');
if (!basePrompt) {
  throw new Error('registry.json mist spelling_filter_prompt.');
}

const candidates = Array.isArray($json.candidates) ? $json.candidates : [];
const lijst = candidates.map((c, i) => {
  const sug = Array.isArray(c.suggesties) ? c.suggesties.join(', ') : '';
  const ctx = String(c.context || '').replace(/"/g, "'");
  return `${i + 1}. woord: "${c.woord}" | context: "${ctx}" | suggesties: ${sug || '(geen)'}`;
}).join('\n') || '(geen kandidaten)';

const chatInput = basePrompt.split('{{kandidaten}}').join(lijst);

return [{ json: { chatInput, candidateCount: candidates.length } }];

function extractText(j) {
  if (!j || typeof j !== 'object') return '';
  if (typeof j.text === 'string' && j.text) return j.text;
  if (typeof j.output === 'string' && j.output) return j.output;
  if (typeof j.answer === 'string' && j.answer) return j.answer;
  if (typeof j.response === 'string' && j.response) return j.response;
  if (typeof j?.message?.content === 'string' && j.message.content) return j.message.content;
  return '';
}
function unwrapJsonLike(s) {
  let t = String(s || '').trim();
  const fence = /^```(?:json)?\s*\r?\n?([\s\S]*?)\r?\n?```$/im;
  const m = t.match(fence);
  if (m) return m[1].trim();
  if (t.startsWith('```')) {
    t = t.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '');
  }
  return t.trim();
}
function parseLlmObject(node) {
  const raw = extractText(node).trim();
  if (raw) {
    try { const p = JSON.parse(unwrapJsonLike(raw)); if (p && typeof p === 'object') return p; } catch {}
    const m = raw.match(/\{[\s\S]*\}/);
    if (m) { try { return JSON.parse(m[0]); } catch {} }
  }
  return null;
}
function unwrapWrappers(parsed, keys) {
  const WRAP = new Set(keys);
  let depth = 0;
  while (
    parsed && typeof parsed === 'object' && !Array.isArray(parsed) &&
    Object.keys(parsed).length === 1 && WRAP.has(Object.keys(parsed)[0]) && depth < 3
  ) {
    parsed = parsed[Object.keys(parsed)[0]];
    depth++;
  }
  return parsed;
}

const node = $input.all()[0]?.json || {};
let parsed = parseLlmObject(node);
if (!parsed && Array.isArray(node.fouten)) parsed = node;
if (!parsed || typeof parsed !== 'object') parsed = { fouten: [] };
parsed = unwrapWrappers(parsed, ['result', 'data', 'response', 'output', 'spelling']);

const rawList = Array.isArray(parsed.fouten)
  ? parsed.fouten
  : (Array.isArray(parsed) ? parsed : []);

const fouten = rawList.map((f) => ({
  woord: String(f?.woord || ''),
  suggestie: String(f?.suggestie || ''),
  context: String(f?.context || ''),
})).filter((f) => f.woord);

return [{ json: { spelling: { fouten, count: fouten.length } } }];

// Combineert de vergelijking en de spellingscontrole tot de webhook-respons.
const comp = $('Parse Comparison JSON').first()?.json?.comparison
  || { bedingen: [], counts: { overgenomen: 0, gewijzigd: 0, ontbreekt: 0, totaal: 0 } };
const spelling = $('Parse Spelling JSON').first()?.json?.spelling
  || { fouten: [], count: 0 };
const meta = $('Aggregate Inputs').first()?.json || {};

// Deterministische check: kwijting/kwitantie telt alleen mee als die direct
// onder een kopje 'Koopprijs' of 'Kwijting'/'Kwitantie' staat. Koppen worden
// herkend als markdown-ATX (## Titel), volledig vetgedrukte regels (**Titel**)
// of korte ALL-CAPS-regels zonder zinseinde (bv. KOOPPRIJS).
// We scannen de VOLLEDIGE bron-markdown uit Extract Markdown (vóór de 12k-clamp
// die alleen voor de LLM-prompts bedoeld is), zodat de check niet wordt beperkt.
let bronMarkdown = '';
try {
  bronMarkdown = $('Extract Markdown').all()
    .filter((it) => it.json?.role === 'bron')
    .map((it) => String(it.json?.markdown || ''))
    .join('\n\n');
} catch (e) {
  bronMarkdown = '';
}
if (!bronMarkdown) bronMarkdown = String(meta.bronMarkdown || '');

const TERM = /kwijting|kwitantie/i;
const HEADING_TERM = /koopprijs|kwijting|kwitantie/i;
function headingText(line) {
  const t = String(line).trim();
  if (!t) return null;
  let m = t.match(/^#{1,6}\s+(.*)$/);
  if (m) return m[1].trim();
  m = t.match(/^\*\*(.+?)\*\*$/);
  if (m) return m[1].trim();
  const letters = t.replace(/[^A-Za-z]/g, '');
  if (t.length <= 60 && letters.length >= 3 && t === t.toUpperCase() && /[A-Z]/.test(t) && !/[.;,:]$/.test(t)) {
    return t;
  }
  return null;
}

let kwijtingGevonden = false;
let inSectie = false;
for (const line of bronMarkdown.split('\n')) {
  const kop = headingText(line);
  if (kop !== null) {
    inSectie = HEADING_TERM.test(kop);
    if (inSectie && TERM.test(kop)) { kwijtingGevonden = true; break; }
    continue;
  }
  if (inSectie && TERM.test(line)) { kwijtingGevonden = true; break; }
}
const brondocument_checks = [{
  id: 'kwijting',
  label: 'Kwijting / kwitantie koopsom',
  gevonden: kwijtingGevonden,
  toelichting: kwijtingGevonden
    ? 'Verwijzing naar kwijting of kwitantie aangetroffen in het brondocument.'
    : 'Geen kwijting of kwitantie aangetroffen in het brondocument.',
}];

return [{
  json: {
    success: true,
    mode: 'aktecontrole',
    zaaknummer: meta.zaaknummer || '',
    akte_filename: meta.akteFilename || '',
    bron_filename: meta.bronFilename || '',
    comparison: comp,
    spelling,
    brondocument_checks,
  },
}];

