catch (err) { throw new Error(`Kon templates-registry niet lezen (${REGISTRY_PATH}): ${err.message}`); }
const basePrompt = String(registry.clausule_extractie_prompt || '');
if (!basePrompt) throw new Error('registry.json mist clausule_extractie_prompt.');
const chatInput = basePrompt.split('{{bron_markdown}}').join(String(input.bronMarkdown || ''));
