if (!parsed || typeof parsed !== 'object') parsed = { bedingen: [] };
parsed = unwrapWrappers(parsed, ['result', 'data', 'response', 'output', 'bedingen_lijst', 'clausules']);
let rawList = Array.isArray(parsed.bedingen) ? parsed.bedingen
