  : (Array.isArray(parsed) ? parsed : []));

const bedingen = rawList.map((b, i) => {
  if (typeof b === 'string') {
    return { id: `beding-${i + 1}`, titel: b.slice(0, 80), brontekst: b };
  }
  const bron = String(pick(b, ['brontekst', 'tekst', 'citaat', 'inhoud', 'beding', 'clausule', 'bepaling', 'text']) || '');
  let titel = String(pick(b, ['titel', 'label', 'naam', 'omschrijving', 'onderwerp', 'title']) || '');
  if (!titel) titel = bron.slice(0, 70) || `Beding ${i + 1}`;
  const id = String(pick(b, ['id', 'slug', 'nummer']) || `beding-${i + 1}`);
  return { id, titel: titel.slice(0, 120), brontekst: bron || titel };
}).filter((b) => b.brontekst);

return [{ json: { bedingen } }];

