const lijst = bedingen
  .map((b, i) => `${i + 1}. [${b.id}] ${b.titel} :: ${String(b.brontekst || '').slice(0, 240)}`)
  .join('\n') || '(geen bedingen gevonden)';

const chatInput = basePrompt
  .split('{{bedingen}}').join(lijst)
  .split('{{akte_markdown}}').join(akte);
