if (!parsed && Array.isArray(node.bedingen)) parsed = node;
if (!parsed || typeof parsed !== 'object') parsed = { bedingen: [] };
parsed = unwrapWrappers(parsed, ['result', 'data', 'response', 'output', 'vergelijking', 'comparison']);
let clsList = Array.isArray(parsed.bedingen) ? parsed.bedingen : (Array.isArray(parsed) ? parsed : []);

const extracted = $('Parse Extracted Bedingen').first()?.json?.bedingen || [];

const byId = {};
clsList.forEach((c) => {
  if (c && typeof c === 'object') {
    const id = String(pick(c, ['id', 'slug', 'nummer']) || '');
    if (id) byId[id] = c;
  }
});

const ALLOWED = new Set(['overgenomen', 'gewijzigd', 'ontbreekt']);
const ALIASES = {
  correct: 'overgenomen', aanwezig: 'overgenomen', identiek: 'overgenomen', ok: 'overgenomen',
  afwijkend: 'gewijzigd', anders: 'gewijzigd', aangepast: 'gewijzigd',
  missing: 'ontbreekt', ontbrekend: 'ontbreekt', afwezig: 'ontbreekt', niet_overgenomen: 'ontbreekt',
};

const bedingen = extracted.map((ex, i) => {
  const c = byId[ex.id] || (typeof clsList[i] === 'object' ? clsList[i] : {}) || {};
  const s = String(pick(c, ['status', 'oordeel', 'resultaat']) || '').trim().toLowerCase().replace(/\s+/g, '_');
  const status = ALLOWED.has(s) ? s : (ALIASES[s] || 'gewijzigd');
  return {
    id: ex.id,
    titel: ex.titel,
    status,
    brontekst: ex.brontekst,
    aktetekst: String(pick(c, ['aktetekst', 'akte', 'aktetext', 'akte_tekst']) || ''),
    toelichting: String(pick(c, ['toelichting', 'reden', 'uitleg', 'motivatie']) || ''),
  };
});

const ORDER = { ontbreekt: 0, gewijzigd: 1, overgenomen: 2 };
bedingen.sort((a, b) => (ORDER[a.status] ?? 9) - (ORDER[b.status] ?? 9));

